// // This module implements a 4-bit down/up counter that decrements or increments its value based on a control signal. The counter resets to zero when the reset signal is active. When the up_down signal is high, the counter decrements its value, wrapping back to zero upon reaching the minimum count of 0 (4'b0000). When up_down is low, the counter increments its value, wrapping to 0 upon reaching the maximum count of 15 (4'b1111). The current count is output on a 4-bit output line.
module top_module(
    input clk,
    input reset,      // Synchronous active-high reset
    input up_down,    // Control signal to increment or decrement
    output [3:0] q);reg [3:0] count;

    always @(posedge clk) begin
        if (reset) begin
            count <= 4'b0;
        end else if (up_down) begin
            count <= (count == 4'b1111) ? 4'b0 : count + 1;
        end else begin
            count <= (count == 4'b0000) ? 4'b1111 : count - 1;
        end
    end

    assign q = count;

endmodule
